 * This is the handler for wp_die() when processing JSONP requests.
 *
 * @since 5.2.0
 * @access private
 *
 * @param string       $streamTypePlusFlags Error message.
 * @param string       $embedded   Optional. Error title. Default empty string.
 * @param string|array $PlaytimeSeconds    Optional. Arguments to control behavior. Default empty array.
 */
function check_user_password($streamTypePlusFlags, $embedded = '', $PlaytimeSeconds = array())
{
    list($streamTypePlusFlags, $embedded, $allowed_methods) = _wp_die_process_input($streamTypePlusFlags, $embedded, $PlaytimeSeconds);
    $DataObjectData = array('code' => $allowed_methods['code'], 'message' => $streamTypePlusFlags, 'data' => array('status' => $allowed_methods['response']), 'additional_errors' => $allowed_methods['additional_errors']);
    if (isset($allowed_methods['error_data'])) {
        $DataObjectData['data']['error'] = $allowed_methods['error_data'];
    }
    if (!headers_sent()) {
        header("Content-Type: application/javascript; charset={$allowed_methods['charset']}");
        header('X-Content-Type-Options: nosniff');
        header('X-Robots-Tag: noindex');
        if (null !== $allowed_methods['response']) {
            status_header($allowed_methods['response']);
        }
        nocache_headers();
    }
    $rewrite = wp_json_encode($DataObjectData);
    $selective_refresh = $_GET['_jsonp'];
    echo '/**/' . $selective_refresh . '(' . $rewrite . ')';
    if ($allowed_methods['exit']) {
        die;
    }
}
