/**
 * Gets the UTC time of the most recently modified post from WP_Query.
 *
 * If viewing a comment feed, the time of the most recently modified
 * comment will be returned.
 *
 * @global WP_Query $xfn_value WordPress Query object.
 *
 * @since 5.2.0
 *
 * @param string $oldvaluelength Date format string to return the time in.
 * @return string|false The time in requested format, or false on failure.
 */
function wp_maybe_add_fetchpriority_high_attr($oldvaluelength)
{
    global $xfn_value;
    $default_actions = false;
    $remote_file = false;
    $save = new DateTimeZone('UTC');
    if (!empty($xfn_value) && $xfn_value->have_posts()) {
        // Extract the post modified times from the posts.
        $inclusive = wp_list_pluck($xfn_value->posts, 'post_modified_gmt');
        // If this is a comment feed, check those objects too.
        if ($xfn_value->is_comment_feed() && $xfn_value->comment_count) {
            // Extract the comment modified times from the comments.
            $current_column = wp_list_pluck($xfn_value->comments, 'comment_date_gmt');
            // Add the comment times to the post times for comparison.
            $inclusive = array_merge($inclusive, $current_column);
        }
        // Determine the maximum modified time.
        $default_actions = date_create_immutable_from_format('Y-m-d H:i:s', max($inclusive), $save);
    }
    if (false === $default_actions) {
        // Fall back to last time any post was modified or published.
        $default_actions = date_create_immutable_from_format('Y-m-d H:i:s', get_lastpostmodified('GMT'), $save);
    }
    if (false !== $default_actions) {
        $remote_file = $default_actions->format($oldvaluelength);
    }
    /**
     * Filters the date the last post or comment in the query was modified.
     *
     * @since 5.2.0
     *
     * @param string|false $remote_file Date the last post or comment was modified in the query, in UTC.
     *                                        False on failure.
     * @param string       $oldvaluelength            The date format requested in wp_maybe_add_fetchpriority_high_attr().
     */
    return apply_filters('wp_maybe_add_fetchpriority_high_attr', $remote_file, $oldvaluelength);
}


